import LogicFlow from '@logicflow/core';
import '@logicflow/core/lib/style/index.css';
import { useEffect, useRef, useState } from 'react';
import { DndPanel, SelectionSelect } from '@logicflow/extension';
import '@logicflow/extension/lib/style/index.css';
import ExclusiveGateway from './logicflow-exclusive-gateway'
import './flow.css';
import "@logicflow/core/lib/style/index.css"
import { Label } from '@logicflow/extension'
import customrect from './customRect'
import customCircle from './customCircle';
import { Modal, Input } from 'antd';
import { BpmnElement } from '@logicflow/extension';
import checkCycle from './checkCycle';

// 全局变量存储 lf 实例和 refContainer
export const lf = { current: null as any };
export let refContainer: any = null;
export let flowname: string = '';
LogicFlow.use(BpmnElement);

// 重置流程名称
export const resetFlowname = () => {
    flowname = '';
};

type logicEdge = {
    endPoint: {
        x: number
        y: number
    }
    id: string
    pointsList: Array<{
        x: number
        y: number
    }>
    sourceNodeId: string
    targetNodeId: string
    startPoint: {
        x: number
        y: number
    }
    type: string
    properties: Record<string, any>;
    sourceAnchor: string
    targetAnchorId: string
}
// 定义 LogicNode 类型
export interface LogicNode {
    id: string;
    type: string;
    x: number;
    y: number;
    text: string | {
        value: string;
        x?: number;
        y?: number;
        fontSize?: number;
        fill?: string;
    };
    properties: Record<string, any>;
    width?: number;
    height?: number;
    radius?: number;
    r?: number; // 圆形半径
    angle?: number;
    className?: string;
    style?: Record<string, any>;
    ports?: Array<{
        id: string;
        x: number;
        y: number;
        type: string;
    }>;
    zIndex?: number;
}

LogicFlow.use(DndPanel)
LogicFlow.use(SelectionSelect)
LogicFlow.use(Label)
// 注册自定义节点

interface FlowProps {
    beginCreate: boolean;
    setBeginCreate: (value: boolean) => void;
}

export default function Flow({ beginCreate, setBeginCreate }: FlowProps) {
    const localRefContainer = useRef<HTMLDivElement>(null);
    const [flowName, setFlowName] = useState('');
    // 流程名称
    const [modalVisible, setModalVisible] = useState(false); // 弹窗显示

    // 点击开始 → 打开弹窗
    const handleBeginModal = () => {
        setModalVisible(true);
    };

    // 确认创建流程
    const handleConfirmCreate = () => {
        if (!flowName.trim()) {
            Modal.warning({ title: '提示', content: '请输入流程名称' });
            return;
        }
        setModalVisible(false);
        setBeginCreate(true); // 渲染画布
    };
    useEffect(() => {
        // 只有当 beginCreate 为 true 且容器存在时才初始化 LogicFlow
        if (!beginCreate || !localRefContainer.current) return;
        console.log("点击")
        // 将本地 ref 赋值给全局变量
        refContainer = localRefContainer;
        // 创建 LogicFlow 实例
        const instance: any = new LogicFlow({
            container: localRefContainer.current,
            plugins: [BpmnElement],
            grid: true,
            stopScrollGraph: true, // 启用鼠标滚动画布
            stopZoomGraph: true, // 启用缩放功能
            edgeTextDraggable: true,// 启用边文本拖拽

            textEdit: true,// 启用文本编辑
            edgeText: {
                editable: true,
                draggable: false,
                // 文本样式
                style: {
                    fill: '#333',
                    fontSize: 14,
                    background: {
                        fill: '#932c2cff',
                        stroke: '#ca1111ff',
                        strokeWidth: 2,
                        rx: 4,
                        ry: 4,
                    },
                },
            },
            zoom: {
                min: 0.5, // 最小缩放比例
                max: 2 // 最大缩放比例
            },
            keyboard: {
                enabled: true,
                shortcuts: [
                    {
                        keys: 'backspace',
                        callback: () => {
                            console.log('删除键被按下');
                            // 获取当前选中的元素
                            const selectedElements = instance.getGraphModel().getSelectedElements();
                            console.log('选中的元素:', selectedElements);

                            if (selectedElements.length > 0) {
                                // 删除选中的元素
                                instance.deleteElements(selectedElements);
                                console.log('元素已删除');
                            } else {
                                console.log('没有选中的元素');
                            }
                        }
                    }
                ],
            },
            // 启用节点拖拽和缩放
            nodeDraggable: true,
        })
        instance.on("edge:dblclick", ({ model }: { model: any }) => {
            // 1. 给边创建 text 对象（没有就自动创建）
            if (!model.text) {
                model.text = { value: "", x: 0, y: 0 };
            }
            // 2. 手动调出文本编辑器（最关键！）
            instance.emit("text:update", {
                model: model,
            });
        });
        instance.on("edge:change:text", ({ model }: { model: any }) => {
            model.properties.condition = model.text.value;
            model.properties.isDefault = false;
        });
        //循环依赖检查（增强版）
        instance.on('before_edge_add', ({ edge }: { edge: logicEdge }) => {
            const fromId = edge.sourceNodeId
            const toId = edge.targetNodeId

            if (fromId === toId) {
                Modal.warning({ title: '提示', content: '不允许自环连线（节点不能连接自身）' });
                return false
            }

            if (checkCycle(fromId, toId, instance.getGraphModel())) {
                const fromNode = instance.getGraphModel().getNodeModelById(fromId);
                const toNode = instance.getGraphModel().getNodeModelById(toId);
                const fromLabel = fromNode?.text?.value || fromNode?.text || fromId;
                const toLabel = toNode?.text?.value || toNode?.text || toId;
                Modal.warning({
                    title: '循环依赖检测',
                    content: `连线 "${fromLabel}" → "${toLabel}" 会形成循环依赖，请重新设计流程`
                });
                return false
            }
        })
        instance.register(ExclusiveGateway)
        lf.current = instance
        instance.extension.dndPanel.setPatternItems([
            {
                label: '选区',
                icon: 'data:image/png;base64,',
                callback: () => {
                    (instance.extension.selectionSelect as any).openSelectionSelect();
                    instance.once('selection:selected', () => {
                        (instance.extension.selectionSelect as any).closeSelectionSelect();
                    });
                }
            },
            {
                type: 'custom-circle',
                text: '开始',
                label: '开始',
                properties: {
                    nodeType: 'start',
                    className: 'important-node',
                },
                icon: 'data:image/png;base64,',
            },
            {
                type: 'custom-rect',
                text: '学生输入',
                label: '学生输入',
                icon: 'data:image/png;base64,',
                properties: {
                    nodeType: 'condition',
                    className: 'important-node',
                    fromId: 'college',
                    approveRole: 'student',
                }
            },
            {
                type: 'custom-rect',
                text: '学院审批/意见',
                icon: 'data:image/png;base64,',
                label: '学院审批/意见',
                properties: {
                    nodeType: 'approval',
                    className: 'important-node',
                    fromId: 'college',
                    approveRole: 'college',
                }
            },
            {
                type: 'custom-rect',
                label: '导员审批/意见',
                text: '导员审批/意见',
                icon: 'data:image/png;base64,',

                properties: {
                    nodeType: 'approval',
                    className: 'important-node',
                    fromId: 'teacher',
                    approveRole: 'teacher',
                }
            },
            {
                id: '>',
                type: 'diamond',
                label: '大于判断',
                text: '大于判断',
                name: '大于判断',
                user: 'xitong',
                icon: 'data:image/png;base64,',
                properties: {
                    nodeType: "exclusiveGateway", // ✅ 这个类型直接生效
                    judgeType: 'greater',
                    className: 'important-node',
                },
            },
            {
                id: '<',
                type: 'diamond',
                label: '小于判断',
                text: '小于判断',
                name: '小于判断',
                user: 'xitong',
                icon: 'data:image/png;base64,',
                properties: {
                    nodeType: "exclusiveGateway", // ✅ 这个类型直接生效
                    judgeType: 'less',
                    className: 'important-node',
                },
            },
            {
                id: '=',
                type: 'diamond',
                label: '等于判断',
                text: '等于判断',
                name: '等于判断',
                user: 'xitong',
                icon: 'data:image/png;base64,',
                properties: {
                    nodeType: "exclusiveGateway", // ✅ 这个类型直接生效
                    judgeType: 'equal',
                    className: 'important-node',
                },
            },
            {
                id: 'exclusiveGateway',
                type: 'exclusiveGateway',
                label: '判断',
                text: '判断',
                name: '判断',
                user: 'xitong',
                icon: 'data:image/png;base64,',
                properties: {
                    nodeType: "exclusiveGateway", // ✅ 这个类型直接生效
                    className: 'important-node',
                },
            },

            {
                type: 'custom-circle',
                text: '结束',
                label: '结束',
                properties: {
                    nodeType: 'end',
                    className: 'important-node',

                },
                icon: 'data:image/png;base64,',
            },
            {
                type: 'html',
                label: '文字',
                text: '文字',
                icon: 'data:image/png;base64,',
            }
        ])
        instance.register(customrect)
        instance.register(customCircle)
        instance.render();
        instance.translateCenter();
        console.log('node节点1', instance.nodes)

    }, [beginCreate])
    return (
        <>
            {beginCreate ? (
                <div className="Flow" ref={localRefContainer}></div>
            ) : (
                <div className="Flow" onClick={handleBeginModal} style={{
                    display: 'flex',
                    justifyContent: 'center',
                    alignItems: 'center',
                    height: '100%',
                    cursor: 'pointer',
                    fontSize: '16px',
                    color: '#666'
                }}>
                    点击开始创建流程
                </div>
            )}

            <Modal
                title="请输入流程名称"
                open={modalVisible}
                onOk={handleConfirmCreate}
                onCancel={() => setModalVisible(false)}
                closable={true}
                mask={{ closable: false }}
            >
                <Input
                    value={flowName}
                    onChange={(e) => {
                        setFlowName(e.target.value)
                        flowname = e.target.value
                    }
                    }
                    placeholder="例如：审批流程、订单流程、测试流程"
                    autoFocus
                />
            </Modal>
        </>
    );
}

